#!/bin/bash
# Nextcloud PostgreSQL Init — idempotent
set -e

psql -v ON_ERROR_STOP=1 -v DB_PASSWORD="$POSTGRES_PASSWORD" --username "$POSTGRES_USER" --dbname "$POSTGRES_DB" <<-EOSQL
  DO
  \$\$
  BEGIN
    IF NOT EXISTS (SELECT FROM pg_catalog.pg_roles WHERE rolname = 'nextcloud') THEN
      CREATE ROLE nextcloud WITH LOGIN PASSWORD :'DB_PASSWORD';
    END IF;
  END
  \$\$;

  SELECT 'CREATE DATABASE nextcloud OWNER nextcloud ENCODING "UTF8" LC_COLLATE = "C" LC_CTYPE = "C" TEMPLATE template0'
  WHERE NOT EXISTS (SELECT FROM pg_database WHERE datname = 'nextcloud')\gexec

  GRANT ALL PRIVILEGES ON DATABASE nextcloud TO nextcloud;
EOSQL
